-- TRIGGER 1 —  20 Prevent Negative Discount 
CREATE TRIGGER before_order_insert
BEFORE INSERT ON orders
FOR EACH ROW
BEGIN
    IF NEW.discount < 0 THEN
      set NEW.discount = 0;
    END IF;
END;

insert into orders values(1014, 138, 231, '2024-01-01', 1200.00, -50.00, 'Credit Card', 30);
select * from orders where order_id = 1014;

---  21 delivery delay warning 
create table delivery_delay_log (
    log_id INT PRIMARY KEY AUTO_INCREMENT,
    order_id INT,
    restaurant_id INT,
    customer_id INT,
    delivery_time INT,
    created timestamp DEFAULT CURRENT_TIMESTAMP
);

create trigger log_delivery_delay
AFTER INSERT ON orders
FOR EACH ROW
BEGIN
    IF NEW.delivery_time > 45 THEN
        INSERT INTO delivery_delay_log (order_id, restaurant_id, customer_id, delivery_time)
        VALUES (NEW.order_id, NEW.restaurant_id, NEW.customer_id, NEW.delivery_time);
    END IF;
END;

